// frontend/src/components/importacion/StepIndicator.jsx
import React from 'react';

const StepIndicator = ({ currentStep, handleStepChange, steps = [
  { id: 1, label: 'Importación' },
  { id: 2, label: 'Validación' },
  { id: 3, label: 'Resultado' }
] }) => {
  return (
    <div className="relative mb-12 mt-6 px-4 max-w-3xl mx-auto">
      {/* Line connecting all steps */}
      <div className="absolute top-5 left-0 right-0 h-0.5 bg-gray-200 -z-10"></div>
      
      {/* Progress line overlay */}
      <div 
        className="absolute top-5 left-0 h-0.5 bg-purple-700 transition-all duration-300 -z-10" 
        style={{ 
          width: currentStep === 1 ? '0%' : 
                 currentStep === 2 ? '50%' : '100%'
        }}
      ></div>
      
      {/* Step indicators */}
      <div className="flex justify-between">
        {steps.map((step, index) => (
          <div 
            key={step.id}
            className={`flex flex-col items-center cursor-pointer ${currentStep >= step.id ? 'text-purple-700' : 'text-gray-400'}`}
            onClick={() => currentStep > step.id && handleStepChange(step.id)}
          >
            {/* Circle with number */}
            <div 
              className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-medium border-2 transition-colors ${
                currentStep > step.id 
                  ? 'bg-purple-700 border-purple-700' 
                  : currentStep === step.id 
                  ? 'bg-purple-700 border-purple-700' 
                  : 'bg-white border-gray-300 text-gray-400'
              }`}
            >
              {currentStep > step.id ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
              ) : (
                step.id
              )}
            </div>
            
            {/* Step label */}
            <span className={`text-sm mt-2 font-medium ${
              currentStep >= step.id ? 'text-purple-700' : 'text-gray-500'
            }`}>
              {step.label}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default StepIndicator;
